import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { Search, SlidersHorizontal, LayoutGrid, List as ListIcon, Car, Fuel, Gauge, Settings } from 'lucide-react';
import { mockVehicles } from '../data/mockVehicles';
import { Vehicle, SortOption } from '../types';

const Inventory: React.FC = () => {
  const [searchParams] = useSearchParams();
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [sortBy, setSortBy] = useState<SortOption>('year_new');
  const [searchTerm, setSearchTerm] = useState('');

  // Filters
  const [makeFilter, setMakeFilter] = useState('');
  const [bodyTypeFilter, setBodyTypeFilter] = useState(searchParams.get('bodyType') || '');

  useEffect(() => {
    const bt = searchParams.get('bodyType');
    if (bt) setBodyTypeFilter(bt);
  }, [searchParams]);

  const filteredVehicles = useMemo(() => {
    let result = [...mockVehicles];

    if (searchTerm) {
      result = result.filter(v => 
        `${v.make} ${v.model}`.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (makeFilter) {
      result = result.filter(v => v.make === makeFilter);
    }

    if (bodyTypeFilter) {
      result = result.filter(v => v.bodyType === bodyTypeFilter);
    }

    // Sort
    result.sort((a, b) => {
      const priceA = typeof a.price === 'number' ? a.price : 999999;
      const priceB = typeof b.price === 'number' ? b.price : 999999;

      switch (sortBy) {
        case 'price_asc': return priceA - priceB;
        case 'price_desc': return priceB - priceA;
        case 'year_new': return b.year - a.year;
        case 'year_old': return a.year - b.year;
        case 'mileage_low': return a.mileage - b.mileage;
        default: return 0;
      }
    });

    return result;
  }, [searchTerm, makeFilter, bodyTypeFilter, sortBy]);

  const uniqueMakes = Array.from(new Set(mockVehicles.map(v => v.make)));

  return (
    <div className="bg-off-white min-h-screen pb-20">
      <div className="bg-black text-white py-16 mb-10">
        <div className="container mx-auto px-6">
          <h1 className="text-4xl font-bold mb-4 brand-font">Browse Inventory</h1>
          <p className="text-gray-400">Discover your perfect match from our 130+ inspected vehicles.</p>
        </div>
      </div>

      <div className="container mx-auto px-6">
        <div className="flex flex-col lg:flex-row gap-10">
          {/* Filters Sidebar */}
          <aside className="w-full lg:w-80 space-y-8">
            <div className="bg-white p-8 rounded-2xl shadow-sm">
              <h3 className="text-lg font-bold mb-6 flex items-center gap-2">
                <SlidersHorizontal size={18} className="text-[#D4AF37]" /> Filter Vehicles
              </h3>

              <div className="space-y-6">
                <div>
                  <label className="text-xs font-bold uppercase tracking-widest text-gray-400 block mb-2">Search Keywords</label>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="e.g. Corolla, Civic..." 
                      className="w-full bg-gray-50 border border-gray-200 p-3 pl-10 rounded-lg outline-none focus:border-[#D4AF37]"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                    <Search className="absolute left-3 top-3.5 text-gray-400" size={18} />
                  </div>
                </div>

                <div>
                  <label className="text-xs font-bold uppercase tracking-widest text-gray-400 block mb-2">Make</label>
                  <select 
                    className="w-full bg-gray-50 border border-gray-200 p-3 rounded-lg outline-none focus:border-[#D4AF37]"
                    value={makeFilter}
                    onChange={(e) => setMakeFilter(e.target.value)}
                  >
                    <option value="">All Makes</option>
                    {uniqueMakes.map(make => <option key={make} value={make}>{make}</option>)}
                  </select>
                </div>

                <div>
                  <label className="text-xs font-bold uppercase tracking-widest text-gray-400 block mb-2">Body Type</label>
                  <select 
                    className="w-full bg-gray-50 border border-gray-200 p-3 rounded-lg outline-none focus:border-[#D4AF37]"
                    value={bodyTypeFilter}
                    onChange={(e) => setBodyTypeFilter(e.target.value)}
                  >
                    <option value="">All Body Types</option>
                    <option value="Sedan">Sedan</option>
                    <option value="Coupe">Coupe</option>
                    <option value="SUV">SUV</option>
                    <option value="Hatchback">Hatchback</option>
                    <option value="Mini-Van">Mini-Van</option>
                    <option value="Truck">Truck</option>
                  </select>
                </div>

                <button 
                  onClick={() => {
                    setSearchTerm('');
                    setMakeFilter('');
                    setBodyTypeFilter('');
                  }}
                  className="w-full text-xs font-bold uppercase tracking-widest text-gray-400 hover:text-[#D4AF37]"
                >
                  Clear All Filters
                </button>
              </div>
            </div>

            <div className="bg-black text-white p-8 rounded-2xl shadow-xl">
              <h4 className="font-bold mb-4">Can't find what you're looking for?</h4>
              <p className="text-gray-400 text-sm mb-6">Use our Car Finder tool and we'll source it for you at wholesale price.</p>
              <Link to="/car-finder" className="block text-center bg-[#D4AF37] text-black py-3 rounded-lg font-bold uppercase tracking-widest text-xs hover:bg-white transition-colors">
                Open Car Finder
              </Link>
            </div>
          </aside>

          {/* Listings Area */}
          <main className="flex-1">
            <div className="bg-white p-4 rounded-2xl shadow-sm mb-8 flex flex-col sm:flex-row justify-between items-center gap-4">
              <p className="text-sm font-medium text-gray-500">
                Showing <span className="text-black font-bold">{filteredVehicles.length}</span> vehicles
              </p>

              <div className="flex items-center gap-4">
                <div className="flex bg-gray-50 p-1 rounded-lg border border-gray-200">
                  <button 
                    onClick={() => setViewMode('grid')}
                    className={`p-2 rounded-md transition-all ${viewMode === 'grid' ? 'bg-white shadow-sm text-[#D4AF37]' : 'text-gray-400'}`}
                  >
                    <LayoutGrid size={18} />
                  </button>
                  <button 
                    onClick={() => setViewMode('list')}
                    className={`p-2 rounded-md transition-all ${viewMode === 'list' ? 'bg-white shadow-sm text-[#D4AF37]' : 'text-gray-400'}`}
                  >
                    <ListIcon size={18} />
                  </button>
                </div>

                <select 
                  className="bg-gray-50 border border-gray-200 p-2 rounded-lg outline-none text-sm font-medium"
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value as SortOption)}
                >
                  <option value="year_new">Newest First</option>
                  <option value="year_old">Oldest First</option>
                  <option value="price_asc">Price: Low to High</option>
                  <option value="price_desc">Price: High to Low</option>
                  <option value="mileage_low">Lowest Mileage</option>
                </select>
              </div>
            </div>

            <div className={viewMode === 'grid' ? 'grid grid-cols-1 md:grid-cols-2 gap-8' : 'flex flex-col gap-6'}>
              {filteredVehicles.map(v => (
                <div key={v.id} className={`bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all border border-gray-100 group ${viewMode === 'list' ? 'flex flex-col md:flex-row' : ''}`}>
                  <Link to={`/vehicle/${v.id}`} className={viewMode === 'list' ? 'w-full md:w-80 h-64 md:h-auto overflow-hidden' : 'h-64 overflow-hidden block relative'}>
                    <img src={v.images[0]} alt={v.make} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                    {v.status === 'Sold' && (
                      <div className="absolute top-4 right-4 bg-red-600 text-white px-3 py-1 rounded text-xs font-bold uppercase">Sold</div>
                    )}
                  </Link>
                  <div className="p-6 flex-1 flex flex-col">
                    <div className="flex justify-between items-start mb-2">
                      <Link to={`/vehicle/${v.id}`} className="hover:text-[#D4AF37] transition-colors">
                        <h3 className="text-xl font-bold">{v.year} {v.make} {v.model}</h3>
                        <p className="text-sm text-gray-500 font-medium">{v.trim}</p>
                      </Link>
                      <span className="text-2xl font-bold text-[#D4AF37]">
                        {typeof v.price === 'number' ? `$${v.price.toLocaleString()}` : v.price}
                      </span>
                    </div>

                    <div className="grid grid-cols-2 gap-4 my-6">
                      <div className="flex items-center gap-2 text-sm text-gray-500"><Gauge size={16} /> {v.mileage.toLocaleString()} km</div>
                      <div className="flex items-center gap-2 text-sm text-gray-500"><Settings size={16} /> {v.transmission}</div>
                      <div className="flex items-center gap-2 text-sm text-gray-500"><Fuel size={16} /> {v.fuelType}</div>
                      <div className="flex items-center gap-2 text-sm text-gray-500"><Car size={16} /> {v.bodyType}</div>
                    </div>

                    <div className="mt-auto pt-6 border-t border-gray-100 flex gap-4">
                      <Link to={`/vehicle/${v.id}`} className="flex-1 bg-gray-50 text-center py-3 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-black hover:text-white transition-all">
                        View Details
                      </Link>
                      <Link to="/apply" className="flex-1 bg-black text-white text-center py-3 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-[#D4AF37] hover:text-black transition-all">
                        Finance
                      </Link>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {filteredVehicles.length === 0 && (
              <div className="bg-white p-20 rounded-2xl text-center shadow-sm">
                <Car size={64} className="mx-auto text-gray-200 mb-6" />
                <h3 className="text-2xl font-bold mb-2">No matching vehicles</h3>
                <p className="text-gray-500">Try adjusting your filters or search terms.</p>
              </div>
            )}
          </main>
        </div>
      </div>
    </div>
  );
};

export default Inventory;

import React, { useState, useEffect, useRef } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import Inventory from './pages/Inventory';
import LoanCalculator from './pages/LoanCalculator';
import AdminDashboard from './pages/AdminDashboard';
import { ENGINE_SOUND_URL } from './constants';
import { Volume2, Play } from 'lucide-react';

const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  const [hasInteracted, setHasInteracted] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const startEngine = () => {
    setHasInteracted(true);
    if (audioRef.current) {
      audioRef.current.play().catch(err => console.error("Playback failed", err));
    }
  };

  return (
    <Router>
      <ScrollToTop />

      {/* Starting Sound Trigger (Splash Screen for Browser Autoplay Policy) */}
      {!hasInteracted && (
        <div className="fixed inset-0 z-[9999] bg-black flex flex-col items-center justify-center p-6">
          <div className="gold-gradient p-1 mb-8 rounded-3xl animate-pulse">
            <div className="bg-black p-8 rounded-[22px] flex flex-col items-center">
               <span className="text-5xl md:text-7xl font-bold brand-font text-white mb-4 italic tracking-tighter">W4Y</span>
               <p className="text-[#D4AF37] font-bold uppercase tracking-[0.4em] text-sm">WHIP4YOU PREMIUM</p>
            </div>
          </div>
          <button 
            onClick={startEngine}
            className="group relative flex flex-col items-center gap-4 transition-all hover:scale-105"
          >
            <div className="w-24 h-24 rounded-full border-4 border-[#D4AF37] flex items-center justify-center text-[#D4AF37] group-hover:bg-[#D4AF37] group-hover:text-black transition-all">
               <Play size={40} fill="currentColor" />
            </div>
            <span className="text-white font-bold uppercase tracking-widest text-xs">Start Engine & Enter</span>
          </button>
          <audio ref={audioRef} src={ENGINE_SOUND_URL} />
        </div>
      )}

      <div className={`flex flex-col min-h-screen ${!hasInteracted ? 'hidden' : ''}`}>
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/inventory" element={<Inventory />} />
            <Route path="/calculator" element={<LoanCalculator />} />
            <Route path="/admin" element={<AdminDashboard />} />
            {/* Fallback routes for demo purposes */}
            <Route path="*" element={<Home />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </Router>
  );
};

export default App;

