import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { Search, SlidersHorizontal, LayoutGrid, List as ListIcon, Car, Fuel, Gauge, Settings, Hash } from 'lucide-react';
import { mockVehicles } from '../data/mockVehicles';
import { Vehicle, SortOption } from '../types';

const Inventory: React.FC = () => {
  const [searchParams] = useSearchParams();
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [sortBy, setSortBy] = useState<SortOption>('year_new');
  const [searchTerm, setSearchTerm] = useState('');
  const [vinSearchTerm, setVinSearchTerm] = useState('');

  // Filters
