                      />
                      <input 
                        type="number" placeholder="Max" 
                        className="w-full bg-gray-50 border border-gray-200 p-2 rounded-lg text-sm outline-none focus:border-[#D4AF37]"
                        value={mileageMax} onChange={(e) => setMileageMax(e.target.value)}
                      />
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div className="bg-black text-white p-6 rounded-2xl shadow-xl">
              <h4 className="font-bold mb-3 text-sm">Need a specific whip?</h4>
              <p className="text-gray-400 text-xs mb-5 leading-relaxed">Our Car Finder team sources premium vehicles at wholesale pricing just for you.</p>
              <Link to="/car-finder" className="block text-center bg-[#D4AF37] text-black py-2.5 rounded-lg font-bold uppercase tracking-widest text-[10px] hover:bg-white transition-colors">
                Start Car Finder
              </Link>
            </div>
          </aside>

          {/* Listings Area */}
          <main className="flex-1">
            <div className="bg-white p-4 rounded-2xl shadow-sm mb-8 flex flex-col sm:flex-row justify-between items-center gap-4 border border-gray-100">
              <p className="text-sm font-medium text-gray-500">
                Found <span className="text-black font-bold">{filteredVehicles.length}</span> matching whips
              </p>

              <div className="flex items-center gap-4">
                <div className="flex bg-gray-50 p-1 rounded-lg border border-gray-200">
                  <button 
                    onClick={() => setViewMode('grid')}
                    className={`p-2 rounded-md transition-all ${viewMode === 'grid' ? 'bg-white shadow-sm text-[#D4AF37]' : 'text-gray-400'}`}
