const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    // If we're navigating to /apply, the Finance component will handle its own scrolling
    if (pathname !== '/apply') {
      window.scrollTo(0, 0);
    }
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  const [hasInteracted, setHasInteracted] = useState(false);
  const [isStarting, setIsStarting] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const startEngine = () => {
    if (isStarting) return;
    setIsStarting(true);

    if (audioRef.current) {
      audioRef.current.volume = 0.6;
      audioRef.current.play().catch(err => {
        console.error("Playback failed", err);
        setHasInteracted(true);
      });

      setTimeout(() => {
        setHasInteracted(true);
      }, 800);
    } else {
      setHasInteracted(true);
    }
  };

  return (
    <Router>
      <ScrollToTop />

      {!hasInteracted && (
        <div className="fixed inset-0 z-[9999] bg-black flex flex-col items-center justify-center p-6 transition-all duration-1000">
          <div className="gold-gradient p-1 mb-8 rounded-3xl animate-pulse">
            <div className="bg-black p-8 rounded-[22px] flex flex-col items-center">
               <span className="text-5xl md:text-7xl font-bold brand-font text-white mb-4 italic tracking-tighter">W4Y</span>
               <p className="text-[#D4AF37] font-bold uppercase tracking-[0.4em] text-sm">WHIP4YOU PREMIUM</p>
            </div>
          </div>

          <div className="h-24 flex flex-col items-center justify-center gap-4">
            {!isStarting ? (
              <button 
                onClick={startEngine}
                className="group relative flex flex-col items-center gap-4 transition-all hover:scale-105"
              >
                <div className="w-20 h-20 rounded-full border-2 border-[#D4AF37] flex items-center justify-center text-[#D4AF37] group-hover:bg-[#D4AF37] group-hover:text-black transition-all">
                   <Play size={32} fill="currentColor" />
                </div>
                <span className="text-white font-bold uppercase tracking-widest text-[10px]">Start Engine & Enter</span>
              </button>
            ) : (
              <div className="flex flex-col items-center gap-3">
                <Loader2 className="text-[#D4AF37] animate-spin" size={32} />
                <span className="text-[#D4AF37] font-black uppercase tracking-widest text-[10px] animate-pulse">Engaging Gear...</span>
              </div>
            )}
          </div>
          <audio ref={audioRef} src={ENGINE_SOUND_URL} preload="auto" />
        </div>
      )}

      <div className={`flex flex-col min-h-screen ${!hasInteracted ? 'hidden' : 'animate-in fade-in duration-1000'}`}>
        <Navbar />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/inventory" element={<Inventory />} />
            <Route path="/vehicle/:id" element={<VehicleDetails />} />
            <Route path="/finance" element={<Finance />} />
            <Route path="/calculator" element={<LoanCalculator />} />
            <Route path="/apply" element={<Finance />} />
            <Route path="/car-finder" element={<Contact type="CarFinder" />} />
            <Route path="/trade-in" element={<Contact type="TradeIn" />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/about" element={<About />} />
            <Route path="/directions" element={<Contact />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="*" element={<Home />} />
          </Routes>
        </main>
        <Footer />
