  const [submitted, setSubmitted] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [vehicleContext, setVehicleContext] = useState<any>(null);

  useEffect(() => {
    const hour = new Date().getHours();
    if (hour >= 11 && hour < 20) {
      setIsLive(true);
    }

    // Check for vehicle ID in URL
    const vId = searchParams.get('vehicleId');
    if (vId) {
      const v = mockVehicles.find(item => item.id === vId);
      if (v) setVehicleContext(v);
    }

    setFormType(type);
  }, [type, searchParams]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (submitted) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center p-6 text-center">
        <div className="bg-white p-10 md:p-24 rounded-[40px] md:rounded-[60px] shadow-[0_0_100px_rgba(212,175,55,0.1)] max-w-2xl border border-gray-100">
