import React, { useState, useRef, useEffect } from 'react';
import { MessageSquare, X, Send, Sparkles, Loader2, Bot, User } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { mockVehicles } from '../data/mockVehicles';

const AIConcierge: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'model'; text: string }[]>([
    { role: 'model', text: 'Welcome to Whip4You. I am your premium concierge. Looking for a specific model or need advice on financing?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const inventoryContext = JSON.stringify(mockVehicles.map(v => ({
        id: v.id, make: v.make, model: v.model, price: v.price, year: v.year, body: v.bodyType, features: v.features
      })));

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-preview-tts',
        contents: userMsg,
        config: {
          systemInstruction: `You are the Whip4You AI Concierge. You are helpful, sophisticated, and professional. 
          Inventory Context: ${inventoryContext}. 
          Rules:
          1. If the user asks for a car type, recommend specific matches from the inventory.
          2. Use automotive terminology (e.g., 'OAC', 'PDI', 'Wholesale').
          3. Keep responses concise and luxury-focused.
          4. If no exact match is found, suggest the 'Car Finder' service.`
        }
      });

      const aiText = response.text || "I apologize, my transmission is experiencing interference. How else can I assist your search?";
      setMessages(prev => [...prev, { role: 'model', text: aiText }]);
    } catch (error) {
      console.error("Gemini Error:", error);
      setMessages(prev => [...prev, { role: 'model', text: "Service temporarily unavailable. Please call (604) 712-1994 for immediate assistance." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      {/* Floating Toggle */}
      <button 
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-8 right-8 z-[100] gold-gradient p-4 rounded-full shadow-3xl hover:scale-110 transition-all group ${isOpen ? 'scale-0' : 'scale-100'}`}
      >
        <div className="bg-black p-3 rounded-full text-[#D4AF37] group-hover:text-white transition-colors">
          <MessageSquare size={24} />
        </div>
        <span className="absolute -top-2 -right-2 bg-red-500 w-4 h-4 rounded-full border-2 border-black animate-pulse"></span>
      </button>

      {/* Chat Window */}
      <div className={`fixed bottom-8 right-8 z-[1000] w-[90vw] md:w-[400px] h-[600px] bg-white rounded-[40px] shadow-4xl flex flex-col overflow-hidden border border-gray-100 transition-all duration-500 origin-bottom-right ${isOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0'}`}>
        {/* Header */}
        <div className="bg-black p-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 gold-gradient rounded-xl flex items-center justify-center">
              <Sparkles size={20} className="text-black" />
            </div>
            <div>
              <h3 className="text-white font-bold brand-font text-sm">W4Y CONCIERGE</h3>
              <p className="text-[8px] text-[#D4AF37] font-black uppercase tracking-[0.3em]">Powered by AI</p>
            </div>
          </div>
          <button onClick={() => setIsOpen(false)} className="text-zinc-500 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-zinc-50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-4 rounded-3xl text-sm leading-relaxed ${m.role === 'user' ? 'bg-black text-white rounded-br-none' : 'bg-white text-zinc-800 shadow-sm border border-gray-100 rounded-bl-none'}`}>
                {m.text}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 rounded-bl-none flex gap-2">
                <Loader2 size={16} className="animate-spin text-[#D4AF37]" />
                <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Consulting Inventory...</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        {/* Input */}
        <div className="p-6 bg-white border-t border-gray-100">
          <div className="relative">
            <input 
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type your inquiry..."
              className="w-full bg-zinc-100 p-4 pr-14 rounded-2xl outline-none focus:bg-white focus:ring-2 focus:ring-[#D4AF37]/20 transition-all text-sm font-medium text-black"
            />
            <button 
              onClick={handleSend}
              className="absolute right-2 top-2 w-10 h-10 bg-black text-[#D4AF37] rounded-xl flex items-center justify-center hover:bg-[#D4AF37] hover:text-black transition-all"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

export default AIConcierge;

