    setCompareIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(i => i !== id);
      }
      if (prev.length >= 3) {
        alert("You can only compare up to 3 vehicles at a time.");
        return prev;
      }
      return [...prev, id];
    });
  };

  const comparedVehicles = useMemo(() => {
    return mockVehicles.filter(v => compareIds.includes(v.id));
  }, [compareIds]);

