                <div>
                  <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400 block mb-2">Keyword Search</label>
                  <div className="relative">
                    <input 
                      type="text" 
                      placeholder="Make, model..." 
                      className="w-full bg-gray-50 border border-gray-200 p-2.5 pl-9 rounded-lg outline-none text-sm focus:border-[#D4AF37]"
