  { id: 'l1', type: 'Finance', name: 'James Wilson', email: 'j.wilson@example.com', phone: '604-555-0123', date: '2 hours ago', status: 'new', message: 'Interested in the Corolla. Looking for 60 month term with 10% down.', priority: 'High' },
  { id: 'l2', type: 'Trade-In', name: 'Sarah Miller', email: 'smiller@webmail.com', phone: '778-555-9876', date: '5 hours ago', status: 'contacted', message: 'I have a 2015 Civic with 120k km. Excellent condition.', priority: 'Medium' },
  { id: 'l3', type: 'General', name: 'Robert Chen', email: 'robert.c@provider.ca', phone: '604-555-4433', date: 'Yesterday', status: 'closed', message: 'Is the 2021 Civic still available for viewing?', priority: 'Low' }
];

const AdminDashboard: React.FC = () => {
