  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingVehicle, setEditingVehicle] = useState<Vehicle | null>(null);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [saveSuccess, setSaveSuccess] = useState(false);

  // Site Configuration State
  const [siteConfig, setSiteConfig] = useState({
    heroHeadline: 'DRIVING DREAMS',
    promoRate: '5.99',
    docFee: '799',
    specialistStatus: 'Online'
  });

  // Derived Metrics
  const metrics = useMemo(() => {
    const totalValuation = vehicles.reduce((acc, v) => acc + (typeof v.price === 'number' ? v.price : 0), 0);
    const newLeads = leads.filter(l => l.status === 'new').length;
    const soldCount = vehicles.filter(v => v.status === 'Sold').length;
    return { totalValuation, newLeads, soldCount };
  }, [vehicles, leads]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') setIsLoggedIn(true);
  };

  const toggleReviewVisibility = (id: string) => {
    setReviews(prev => prev.map(r => r.id === id ? { ...r, visible: !r.visible } : r));
  };

  const handleDeleteVehicle = (id: string) => {
    if (window.confirm("Permanent decommissioning of asset? This cannot be undone.")) {
      setVehicles(prev => prev.filter(v => v.id !== id));
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-6">
        <form onSubmit={handleLogin} className="bg-white p-12 rounded-[40px] shadow-2xl w-full max-w-md text-center border border-white/10">
          <div className="gold-gradient w-24 h-24 rounded-3xl flex items-center justify-center mx-auto mb-10 shadow-xl">
            <ShieldCheck size={40} className="text-black" />
