import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, Car, FileText, Settings, LogOut, 
  Plus, Trash2, Edit3, CheckCircle, Clock, X, 
  Phone, Mail, User, MessageSquare, AlertTriangle,
  TrendingUp, BarChart3, Eye, EyeOff, Star, ShieldCheck,
  Percent, DollarSign, Type, ClipboardEdit, Save
} from 'lucide-react';
import { mockVehicles } from '../data/mockVehicles';
import { MOCK_REVIEWS } from '../constants';
import { Vehicle } from '../types';

interface Lead {
  id: string;
  type: 'Finance' | 'Trade-In' | 'General' | 'Car Finder';
  name: string;
  email: string;
  phone: string;
  date: string;
  status: 'open' | 'inProgress' | 'done';
  message: string;
  priority: 'High' | 'Medium' | 'Low';
  remarks?: string;
}

const MOCK_LEADS: Lead[] = [
  { id: 'l1', type: 'Finance', name: 'James Wilson', email: 'j.wilson@example.com', phone: '604-555-0123', date: '2 hours ago', status: 'open', message: 'Interested in the Corolla. Looking for 60 month term with 10% down.', priority: 'High', remarks: '' },
  { id: 'l2', type: 'Trade-In', name: 'Sarah Miller', email: 'smiller@webmail.com', phone: '778-555-9876', date: '5 hours ago', status: 'inProgress', message: 'I have a 2015 Civic with 120k km. Excellent condition.', priority: 'Medium', remarks: 'Awaiting photos of the Civic.' },
  { id: 'l3', type: 'General', name: 'Robert Chen', email: 'robert.c@provider.ca', phone: '604-555-4433', date: 'Yesterday', status: 'done', message: 'Is the 2021 Civic still available for viewing?', priority: 'Low', remarks: 'Client viewed. Not interested in coupe.' }
];

const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'inventory' | 'leads' | 'reviews' | 'config'>('overview');
  const [vehicles, setVehicles] = useState<Vehicle[]>(mockVehicles);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS);
  const [reviews, setReviews] = useState(MOCK_REVIEWS.map(r => ({ ...r, visible: true })));
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingVehicle, setEditingVehicle] = useState<Vehicle | null>(null);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [saveSuccess, setSaveSuccess] = useState(false);

  // Lead Editing State
  const [leadRemarks, setLeadRemarks] = useState('');
  const [leadStatus, setLeadStatus] = useState<Lead['status']>('open');

  // Site Configuration State
  const [siteConfig, setSiteConfig] = useState({
    heroHeadline: 'DRIVING DREAMS',
    promoRate: '5.99',
    docFee: '799',
    specialistStatus: 'Online'
  });

  // Derived Metrics
  const metrics = useMemo(() => {
    const totalValuation = vehicles.reduce((acc, v) => acc + (typeof v.price === 'number' ? v.price : 0), 0);
    const pendingLeads = leads.filter(l => l.status !== 'done').length;
    const soldCount = vehicles.filter(v => v.status === 'Sold').length;
    return { totalValuation, pendingLeads, soldCount };
  }, [vehicles, leads]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin123') setIsLoggedIn(true);
  };

  const toggleReviewVisibility = (id: string) => {
    setReviews(prev => prev.map(r => r.id === id ? { ...r, visible: !r.visible } : r));
  };

  const handleDeleteVehicle = (id: string) => {
    if (window.confirm("Permanent decommissioning of asset? This cannot be undone.")) {
      setVehicles(prev => prev.filter(v => v.id !== id));
    }
  };

  const handleSelectLead = (lead: Lead) => {
    setSelectedLead(lead);
    setLeadRemarks(lead.remarks || '');
    setLeadStatus(lead.status);
  };

  const handleUpdateLead = () => {
    if (!selectedLead) return;

    setLeads(prev => prev.map(l => 
      l.id === selectedLead.id 
        ? { ...l, status: leadStatus, remarks: leadRemarks } 
        : l
    ));

    setSaveSuccess(true);
    setTimeout(() => {
      setSaveSuccess(false);
      setSelectedLead(null);
    }, 800);
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black p-6">
        <form onSubmit={handleLogin} className="bg-white p-12 rounded-[40px] shadow-2xl w-full max-w-md text-center border border-white/10">
          <div className="gold-gradient w-24 h-24 rounded-3xl flex items-center justify-center mx-auto mb-10 shadow-xl">
            <ShieldCheck size={40} className="text-black" />
          </div>
          <h2 className="text-3xl font-bold mb-4 brand-font italic uppercase">Secure Portal</h2>
          <p className="text-zinc-400 mb-10 uppercase tracking-[0.3em] text-[10px] font-bold">W4Y Backoffice Environment</p>
          <input 
            required
