import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import dotenv from 'dotenv';
import rateLimit from 'express-rate-limit';

// Initialize configuration
dotenv.config();

const app = express();
const PORT = process.env.PORT || 5000;

// Security & Utility Middleware
app.use(helmet()); // Secure HTTP headers
app.use(cors()); // Enable Cross-Origin Resource Sharing
app.use(morgan('dev')); // Log requests to console
app.use(express.json()); // Parse JSON bodies

// Rate Limiting to prevent API abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: 'Too many requests from this IP, please try again after 15 minutes'
});
app.use('/api/', limiter);

// Basic Health Check Route
app.get('/health', (req, res) => {
  res.status(200).json({ 
    status: 'Operational', 
    timestamp: new Date().toISOString(),
    service: 'Whip4You Systems'
  });
});

// Mock Leads Database for CRM (In a real app, use MongoDB/Postgres)
let leads = [
  { id: 'l1', type: 'Finance', name: 'James Wilson', status: 'open', message: 'Interested in the Corolla.', priority: 'High', remarks: '' },
  { id: 'l2', type: 'Trade-In', name: 'Sarah Miller', status: 'inProgress', message: '2015 Civic trade appraisal.', priority: 'Medium', remarks: 'Awaiting photos.' }
];

// API Routes
app.get('/api/leads', (req, res) => {
  res.json(leads);
});

app.post('/api/leads', (req, res) => {
  const newLead = {
    id: `l${Date.now()}`,
    date: new Date().toLocaleDateString(),
    status: 'open',
    ...req.body
  };
  leads.unshift(newLead);
  res.status(201).json(newLead);
});

