const __dirname = path.dirname(fileURLToPath(import.meta.url));
const distDir = path.join(__dirname, '../dist');

async function build() {
  console.log('🏗️  Starting Industry-Level Backend Build...');

  try {
    // 1. Ensure dist directory exists
    if (!fs.existsSync(distDir)) {
      fs.mkdirSync(distDir);
    }

    // 2. Bundle and Minify using esbuild
    console.log('📦 Bundling and Minifying with esbuild...');
    const result = await esbuild.build({
      entryPoints: [path.join(__dirname, '../index.js')],
      bundle: true,
      minify: true,
      platform: 'node',
      format: 'esm',
      target: 'node20',
      outfile: path.join(distDir, 'server.bundle.js'),
      external: ['mongoose', 'express', 'cors', 'helmet', 'morgan', 'dotenv', 'winston', 'bcryptjs', 'jsonwebtoken'], // Keep external deps separate for stability
    });

    // 3. Advanced Uglification / Obfuscation
    console.log('🔒 Applying Advanced Obfuscation...');
    const bundledCode = fs.readFileSync(path.join(distDir, 'server.bundle.js'), 'utf8');

    const obfuscationResult = JavaScriptObfuscator.obfuscate(bundledCode, {
      compact: true,
      controlFlowFlattening: true,
      controlFlowFlatteningThreshold: 0.75,
      deadCodeInjection: true,
      deadCodeInjectionThreshold: 0.4,
      debugProtection: false,
      disableConsoleOutput: true,
      identifierNamesGenerator: 'hexadecimal',
      log: false,
      numbersToExpressions: true,
      renameGlobals: false,
      selfDefending: true,
      simplify: true,
      splitStrings: true,
      splitStringsChunkLength: 10,
      stringArray: true,
      stringArrayCallsTransform: true,
      stringArrayEncoding: ['base64'],
      stringArrayThreshold: 0.75,
      transformObjectKeys: true,
      unicodeEscapeSequence: false
    });

    fs.writeFileSync(path.join(distDir, 'server.min.js'), obfuscationResult.getObfuscatedCode());

    // Clean up intermediate bundle
    fs.unlinkSync(path.join(distDir, 'server.bundle.js'));

    console.log('✅ Build Complete! Production server ready at: backend/dist/server.min.js');
  } catch (error) {
    console.error('❌ Build Failed:', error);
    process.exit(1);
  }
}

