import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import morgan from 'morgan';
import dotenv from 'dotenv';
import connectDB from './config/db.js';
import logger from './utils/logger.js';
import { errorHandler, notFound } from './middleware/errorMiddleware.js';

// Route Imports
import leadRoutes from './routes/leadRoutes.js';
import vehicleRoutes from './routes/vehicleRoutes.js';
import authRoutes from './routes/authRoutes.js';
import reviewRoutes from './routes/reviewRoutes.js';
import configRoutes from './routes/configRoutes.js';

dotenv.config();

// Initialize DB
connectDB();

const app = express();

// Security & Utility Middleware
app.use(helmet());
app.use(cors());

// Log HTTP requests through winston
app.use(morgan('combined', { 
  stream: { write: (message) => logger.info(message.trim()) } 
}));

app.use(express.json());

// Main API Routes
app.use('/api/auth', authRoutes);
app.use('/api/leads', leadRoutes);
app.use('/api/vehicles', vehicleRoutes);
app.use('/api/reviews', reviewRoutes);
app.use('/api/config', configRoutes);

app.get('/api/health', (req, res) => res.json({ status: 'up' }));

// Error Handling Middleware
app.use(notFound);
app.use(errorHandler);

const PORT = process.env.PORT || 5000;
app.listen(PORT, () => {
  logger.info(`🚀 WHIP4YOU Server running on port ${PORT}`);
});

const BASE_URL = '/api';

const getHeaders = () => {
  const token = localStorage.getItem('w4y_admin_token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { 'Authorization': `Bearer ${token}` } : {}),
  };
};

export const api = {
  // Auth
  login: (credentials: any) => 
    fetch(`${BASE_URL}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(credentials)
    }).then(res => res.json()),

  // Vehicles
  getVehicles: () => 
    fetch(`${BASE_URL}/vehicles`).then(res => res.json()),

  getVehicleById: (id: string) => 
    fetch(`${BASE_URL}/vehicles/${id}`).then(res => res.json()),

  createVehicle: (data: any) =>
    fetch(`${BASE_URL}/vehicles`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(res => res.json()),

  deleteVehicle: (id: string) =>
    fetch(`${BASE_URL}/vehicles/${id}`, {
      method: 'DELETE',
      headers: getHeaders()
    }),

  // Leads
  getLeads: () => 
    fetch(`${BASE_URL}/leads`, { headers: getHeaders() }).then(res => res.json()),

  createLead: (data: any) => 
    fetch(`${BASE_URL}/leads`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    }).then(res => res.json()),

  updateLead: (id: string, data: any) =>
    fetch(`${BASE_URL}/leads/${id}`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(res => res.json()),

  // Reviews
  getReviews: () => 
    fetch(`${BASE_URL}/reviews`).then(res => res.json()),

  getAdminReviews: () =>
    fetch(`${BASE_URL}/reviews/admin`, { headers: getHeaders() }).then(res => res.json()),

  updateReview: (id: string, data: any) =>
    fetch(`${BASE_URL}/reviews/${id}`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(res => res.json()),

  // Config
  getConfig: () => 
    fetch(`${BASE_URL}/config`).then(res => res.json()),

  updateConfig: (data: any) =>
    fetch(`${BASE_URL}/config`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(res => res.json()),
};

import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { 
  Search, SlidersHorizontal, LayoutGrid, List as ListIcon, 
  Car, Fuel, Gauge, Settings, Hash, Palette, Calendar, 
  DollarSign, ArrowRightLeft, X, Check, Info, Plus, Loader2
} from 'lucide-react';
import { api } from '../api';
import { Vehicle, SortOption } from '../types';

const Inventory: React.FC = () => {
  const [searchParams] = useSearchParams();
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [sortBy, setSortBy] = useState<SortOption>('year_new');
  const [searchTerm, setSearchTerm] = useState('');
  const [vinSearchTerm, setVinSearchTerm] = useState('');
  const [vehicles, setVehicles] = useState<Vehicle[]>([]);
  const [loading, setLoading] = useState(true);

  // Comparison State
  const [compareIds, setCompareIds] = useState<string[]>([]);
  const [isCompareModalOpen, setIsCompareModalOpen] = useState(false);

  // Filters
  const [makeFilter, setMakeFilter] = useState('');
  const [bodyTypeFilter, setBodyTypeFilter] = useState(searchParams.get('bodyType') || '');
  const [transmissionFilter, setTransmissionFilter] = useState('');
  const [colorFilter, setColorFilter] = useState('');

  // Range Filters
  const [yearMin, setYearMin] = useState('');
  const [yearMax, setYearMax] = useState('');
  const [priceMin, setPriceMin] = useState('');
  const [priceMax, setPriceMax] = useState('');
  const [mileageMin, setMileageMin] = useState('');
  const [mileageMax, setMileageMax] = useState('');

  useEffect(() => {
    api.getVehicles().then(data => {
      setVehicles(data);
      setLoading(false);
    });
  }, []);

  useEffect(() => {
    const bt = searchParams.get('bodyType');
    if (bt) setBodyTypeFilter(bt);
  }, [searchParams]);

  const filteredVehicles = useMemo(() => {
    let result = [...vehicles];

    if (searchTerm) {
      result = result.filter(v => 
        `${v.make} ${v.model}`.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (vinSearchTerm) {
      result = result.filter(v => 
        v.vin.toLowerCase().includes(vinSearchTerm.toLowerCase())
      );
    }

    if (makeFilter) result = result.filter(v => v.make === makeFilter);
    if (bodyTypeFilter) result = result.filter(v => v.bodyType === bodyTypeFilter);
    if (transmissionFilter) result = result.filter(v => v.transmission === transmissionFilter);
    if (colorFilter) result = result.filter(v => v.exteriorColor === colorFilter);

    if (yearMin) result = result.filter(v => v.year >= parseInt(yearMin));
    if (yearMax) result = result.filter(v => v.year <= parseInt(yearMax));

    if (priceMin) result = result.filter(v => {
      const p = typeof v.price === 'number' ? v.price : 0;
      return p >= parseInt(priceMin);
    });
    if (priceMax) result = result.filter(v => {
      const p = typeof v.price === 'number' ? v.price : 9999999;
      return p <= parseInt(priceMax);
    });

    if (mileageMin) result = result.filter(v => v.mileage >= parseInt(mileageMin));
    if (mileageMax) result = result.filter(v => v.mileage <= parseInt(mileageMax));

    result.sort((a, b) => {
      const priceA = typeof a.price === 'number' ? a.price : 999999;
      const priceB = typeof b.price === 'number' ? b.price : 999999;

      switch (sortBy) {
        case 'price_asc': return priceA - priceB;
        case 'price_desc': return priceB - priceA;
        case 'year_new': return b.year - a.year;
        case 'year_old': return a.year - b.year;
        case 'mileage_low': return a.mileage - b.mileage;
        default: return 0;
      }
    });

    return result;
  }, [vehicles, searchTerm, vinSearchTerm, makeFilter, bodyTypeFilter, transmissionFilter, colorFilter, yearMin, yearMax, priceMin, priceMax, mileageMin, mileageMax, sortBy]);

  const activeFilters = useMemo(() => {
    const chips: { label: string; key: string; value: any }[] = [];
    if (makeFilter) chips.push({ label: makeFilter, key: 'make', value: setMakeFilter });
    if (bodyTypeFilter) chips.push({ label: bodyTypeFilter, key: 'body', value: setBodyTypeFilter });
    if (transmissionFilter) chips.push({ label: transmissionFilter, key: 'trans', value: setTransmissionFilter });
    if (colorFilter) chips.push({ label: colorFilter, key: 'color', value: setColorFilter });
    if (searchTerm) chips.push({ label: `"${searchTerm}"`, key: 'search', value: setSearchTerm });
    return chips;
  }, [makeFilter, bodyTypeFilter, transmissionFilter, colorFilter, searchTerm]);

  const uniqueMakes = Array.from(new Set(vehicles.map(v => v.make))).sort();
  const uniqueTransmissions = Array.from(new Set(vehicles.map(v => v.transmission))).sort();
  const uniqueColors = Array.from(new Set(vehicles.map(v => v.exteriorColor))).sort();

  const handleClearFilters = () => {
    setSearchTerm('');
    setVinSearchTerm('');
    setMakeFilter('');
    setBodyTypeFilter('');
    setTransmissionFilter('');
    setColorFilter('');
    setYearMin('');
    setYearMax('');
    setPriceMin('');
    setPriceMax('');
    setMileageMin('');
    setMileageMax('');
  };

  const toggleCompare = (id: string) => {
    setCompareIds(prev => {
      if (prev.includes(id)) return prev.filter(i => i !== id);
      if (prev.length >= 3) return prev;
      return [...prev, id];
    });
  };

  const comparedVehicles = useMemo(() => {
    return vehicles.filter(v => compareIds.includes(v.id));
  }, [compareIds, vehicles]);

  if (loading) {
    return (
      <div className="min-h-screen bg-off-white flex flex-col items-center justify-center gap-6">
        <Loader2 className="text-[#D4AF37] animate-spin" size={48} />
        <p className="font-bold text-black brand-font uppercase tracking-widest text-xs">Scanning Fleet Registry...</p>
      </div>
    );
  }

  return (
    <div className="bg-off-white min-h-screen pb-20 relative text-gray-900">
      <div className="bg-black text-white py-16 mb-10">
        <div className="container mx-auto px-6">
          <h1 className="text-4xl font-bold mb-4 brand-font italic">Browse Inventory</h1>
          <p className="text-gray-400">Discover your perfect match from our premium inspected vehicles.</p>
        </div>
      </div>

      <div className="container mx-auto px-6">
        <div className="flex flex-col lg:flex-row gap-10">
          <aside className="w-full lg:w-80 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold flex items-center gap-2">
                  <SlidersHorizontal size={18} className="text-[#D4AF37]" /> Filters
                </h3>
                <button onClick={handleClearFilters} className="text-[10px] font-bold uppercase tracking-widest text-[#D4AF37] hover:text-black transition-colors">Reset</button>
              </div>

              <div className="space-y-6">
                <div className="bg-gray-50 p-4 rounded-xl border border-gray-100 flex items-start gap-3">
                  <Info size={16} className="text-[#D4AF37] flex-shrink-0 mt-0.5" />
                  <div>
                    <h4 className="text-[10px] font-bold uppercase tracking-widest mb-1">Comparison Tool</h4>
                    <p className="text-[10px] text-gray-500 leading-relaxed italic">Select up to 3 whips using the <ArrowRightLeft size={10} className="inline mx-0.5" /> icon on any car to compare specs side-by-side.</p>
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400 block mb-2">Keyword Search</label>
                  <div className="relative">
                    <input type="text" placeholder="Make, model..." className="w-full bg-gray-50 border border-gray-200 p-2.5 pl-9 rounded-lg outline-none text-sm focus:border-[#D4AF37]" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                    <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400 block mb-2">VIN Search</label>
                  <div className="relative">
                    <input type="text" placeholder="Enter VIN..." className="w-full bg-gray-50 border border-gray-200 p-2.5 pl-9 rounded-lg outline-none text-sm focus:border-[#D4AF37]" value={vinSearchTerm} onChange={(e) => setVinSearchTerm(e.target.value)} />
                    <Hash className="absolute left-3 top-2.5 text-gray-400" size={16} />
                  </div>
                </div>

                <div className="h-px bg-gray-100" />

                <div className="grid grid-cols-1 gap-4">
                  <div>
                    <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400 block mb-2">Make</label>
                    <select className="w-full bg-gray-50 border border-gray-200 p-2.5 rounded-lg outline-none text-sm focus:border-[#D4AF37]" value={makeFilter} onChange={(e) => setMakeFilter(e.target.value)}>
                      <option value="">All Makes</option>
                      {uniqueMakes.map(make => <option key={make} value={make}>{make}</option>)}
                    </select>
                  </div>

                  <div>
                    <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400 block mb-2">Body Type</label>
                    <select className="w-full bg-gray-50 border border-gray-200 p-2.5 rounded-lg outline-none text-sm focus:border-[#D4AF37]" value={bodyTypeFilter} onChange={(e) => setBodyTypeFilter(e.target.value)}>
                      <option value="">All Types</option>
                      <option value="Sedan">Sedan</option>
                      <option value="Coupe">Coupe</option>
                      <option value="SUV">SUV</option>
                      <option value="Hatchback">Hatchback</option>
                      <option value="Mini-Van">Mini-Van</option>
                      <option value="Truck">Truck</option>
                    </select>
                  </div>
                </div>

                <div className="space-y-4">
                  <div>
                    <label className="text-[10px] font-bold uppercase tracking-widest text-gray-400 block mb-2 flex items-center gap-1"><DollarSign size={12} /> Price Range</label>
                    <div className="grid grid-cols-2 gap-2">
                      <input type="number" placeholder="Min" className="w-full bg-gray-50 border border-gray-200 p-2 rounded-lg text-sm outline-none focus:border-[#D4AF37]" value={priceMin} onChange={(e) => setPriceMin(e.target.value)} />
                      <input type="number" placeholder="Max" className="w-full bg-gray-50 border border-gray-200 p-2 rounded-lg text-sm outline-none focus:border-[#D4AF37]" value={priceMax} onChange={(e) => setPriceMax(e.target.value)} />
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </aside>

          <main className="flex-1">
            <div className="bg-white p-4 rounded-2xl shadow-sm mb-8 flex flex-col sm:flex-row justify-between items-center gap-4 border border-gray-100">
              <p className="text-sm font-medium text-gray-500">Found <span className="text-black font-bold">{filteredVehicles.length}</span> matching whips</p>
              <div className="flex items-center gap-4">
                <select className="bg-gray-50 border border-gray-200 p-2 rounded-lg outline-none text-xs font-bold uppercase tracking-widest" value={sortBy} onChange={(e) => setSortBy(e.target.value as SortOption)}>
                  <option value="year_new">Newest First</option>
                  <option value="year_old">Oldest First</option>
                  <option value="price_asc">Price: Low to High</option>
                  <option value="price_desc">Price: High to Low</option>
                  <option value="mileage_low">Lowest Mileage</option>
                </select>
              </div>
            </div>

            <div className={viewMode === 'grid' ? 'grid grid-cols-1 md:grid-cols-2 gap-8' : 'flex flex-col gap-6'}>
              {filteredVehicles.map(v => (
                <div key={v.id} className="bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all border border-gray-100 group flex flex-col">
                  <div className="relative h-64 overflow-hidden block">
                    <Link to={`/vehicle/${v.id}`} className="block h-full">
                      <img src={v.images[0]} alt={v.make} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                    </Link>
                    <button onClick={() => toggleCompare(v.id)} className={`absolute bottom-4 left-4 py-2 px-3 rounded-full shadow-lg transition-all flex items-center gap-2 ${compareIds.includes(v.id) ? 'bg-[#D4AF37] text-black' : 'bg-black/60 text-white hover:bg-black'}`}>
                      {compareIds.includes(v.id) ? <Check size={18} /> : <ArrowRightLeft size={18} />}
                    </button>
                  </div>
                  <div className="p-6">
                    <div className="flex justify-between items-start mb-2">
                      <Link to={`/vehicle/${v.id}`} className="hover:text-[#D4AF37] transition-colors">
                        <h3 className="text-xl font-bold text-black">{v.year} {v.make} {v.model}</h3>
                        <p className="text-sm text-gray-400 font-medium">{v.trim}</p>
                      </Link>
                      <span className="text-2xl font-bold text-[#D4AF37] brand-font">
                        {typeof v.price === 'number' ? `$${v.price.toLocaleString()}` : v.price}
                      </span>
                    </div>
                    <div className="mt-auto pt-6 border-t border-gray-100 flex gap-4">
                      <Link to={`/vehicle/${v.id}`} className="flex-1 bg-gray-50 text-center py-3 rounded-xl font-bold text-[10px] uppercase tracking-widest text-black">View Details</Link>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </main>
        </div>
      </div>
    </div>
  );
};

export default Inventory;

