const BASE_URL = '/api';

const getHeaders = () => {
  const token = localStorage.getItem('w4y_admin_token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { 'Authorization': `Bearer ${token}` } : {}),
  };
};

/**
 * Safely handles fetch responses by reading body as text first.
 * Prevents "Unexpected character" errors when server returns non-JSON or empty bodies.
 */
const handleResponse = async (res: Response) => {
  const text = await res.text();

  if (!res.ok) {
    // Attempt to extract error message from JSON if possible, otherwise use raw text
    try {
      const errorData = JSON.parse(text);
      throw new Error(errorData.message || `Request failed with status ${res.status}`);
    } catch {
      throw new Error(text || `Request failed with status ${res.status}`);
    }
  }

  if (!text || res.status === 204) {
    return null;
  }

  try {
    return JSON.parse(text);
  } catch (e) {
    // If not JSON, return as plain text
    return text;
  }
};

export const api = {
  // Auth
  login: (credentials: any) => 
    fetch(`${BASE_URL}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(credentials)
    }).then(handleResponse),

  // Vehicles
  getVehicles: () => 
    fetch(`${BASE_URL}/vehicles`).then(handleResponse),

  getVehicleById: (id: string) => 
    fetch(`${BASE_URL}/vehicles/${id}`).then(handleResponse),

  createVehicle: (data: any) =>
    fetch(`${BASE_URL}/vehicles`, {
      method: 'POST',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(handleResponse),

  deleteVehicle: (id: string) =>
    fetch(`${BASE_URL}/vehicles/${id}`, {
      method: 'DELETE',
      headers: getHeaders()
    }).then(handleResponse),

  // Leads
  getLeads: () => 
    fetch(`${BASE_URL}/leads`, { headers: getHeaders() }).then(handleResponse),

  createLead: (data: any) => 
    fetch(`${BASE_URL}/leads`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    }).then(handleResponse),

  updateLead: (id: string, data: any) =>
    fetch(`${BASE_URL}/leads/${id}`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(handleResponse),

  // Reviews
  getReviews: () => 
    fetch(`${BASE_URL}/reviews`).then(handleResponse),

  getAdminReviews: () =>
    fetch(`${BASE_URL}/reviews/admin`, { headers: getHeaders() }).then(handleResponse),

  updateReview: (id: string, data: any) =>
    fetch(`${BASE_URL}/reviews/${id}`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(handleResponse),

  // Config
  getConfig: () => 
    fetch(`${BASE_URL}/config`).then(handleResponse),

  updateConfig: (data: any) =>
    fetch(`${BASE_URL}/config`, {
      method: 'PATCH',
      headers: getHeaders(),
      body: JSON.stringify(data)
    }).then(handleResponse),
};

