          <div className="flex items-center gap-3">
            <div className="w-10 h-10 gold-gradient rounded-xl flex items-center justify-center">
              <Sparkles size={20} className="text-black" />
            </div>
            <div>
              <h3 className="text-white font-bold brand-font text-sm">W4Y CONCIERGE</h3>
              <p className="text-[8px] text-[#D4AF37] font-black uppercase tracking-[0.3em]">Powered by AI</p>
            </div>
          </div>
          <button onClick={() => setIsOpen(false)} className="text-zinc-500 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-zinc-50">
          {messages.map((m, i) => (
            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] p-4 rounded-3xl text-sm leading-relaxed ${m.role === 'user' ? 'bg-black text-white rounded-br-none' : 'bg-white text-zinc-800 shadow-sm border border-gray-100 rounded-bl-none'}`}>
                {m.text}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white p-4 rounded-3xl shadow-sm border border-gray-100 rounded-bl-none flex gap-2">
                <Loader2 size={16} className="animate-spin text-[#D4AF37]" />
                <span className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Consulting Inventory...</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        {/* Input */}
        <div className="p-6 bg-white border-t border-gray-100">
          <div className="relative">
            <input 
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type your inquiry..."
              className="w-full bg-zinc-100 p-4 pr-14 rounded-2xl outline-none focus:bg-white focus:ring-2 focus:ring-[#D4AF37]/20 transition-all text-sm font-medium text-black"
            />
