    const hour = new Date().getHours();
    if (hour >= 11 && hour < 20) {
      setIsLive(true);
    }

    // Check for vehicle ID in URL
    const vId = searchParams.get('vehicleId');
    if (vId) {
      const v = mockVehicles.find(item => item.id === vId);
